challenge.referenceSolution:
```cpp
#include <inplace_vector>
#include <algorithm>
#include <ranges>
#include <print>

std::inplace_vector<int, 5> top_k(std::ranges::input_range auto&& r) {
    std::inplace_vector<int, 5> result;
    for (int x : r) {
        if (result.size() < 5) {
            result.push_back(x);
            std::push_heap(result.begin(), result.end(), std::greater<>{});
        } else if (x > result.front()) {
            std::pop_heap(result.begin(), result.end(), std::greater<>{});
            result.back() = x;
            std::push_heap(result.begin(), result.end(), std::greater<>{});
        }
    }
    std::sort_heap(result.begin(), result.end(), std::greater<>{});
    return result;
}

int main() {
    int data[] = {3, 1, 4, 1, 5, 9, 2, 6, 5, 3, 5};
    auto top = top_k(data);
    for (int x : top) std::print("{} ", x);
    std::println("");
}
```

