// Note: std::hive is not yet implemented in any compiler (P0447)
// Code follows the proposal specification
#include <hive>
#include <print>

int main() {
    std::hive<int> h;
    auto it1 = h.insert(10);
    auto it2 = h.insert(20);
    auto it3 = h.insert(30);

    h.erase(it2); // erase 20; it1 and it3 remain valid

    std::println("size={}", h.size()); // 2
    for (int x : h)
        std::print("{} ", x); // 10 30 (order may vary)
    std::println("");
}

// Note: std::hive is not yet implemented in any compiler (P0447)
// Code follows the proposal specification
#include <hive>
#include <print>
#include <string>

int main() {
    std::hive<std::string> h;
    auto it = h.insert("hello");
    const std::string* ptr = &(*it); // raw pointer to element

    // Insert a thousand more elements — ptr stays valid
    for (int i = 0; i < 1000; ++i)
        h.insert("item" + std::to_string(i));

    // With std::vector, push_back could have invalidated ptr via reallocation.
    // With std::hive, the element's address never changes.
    std::println("{}", *ptr); // still "hello"
    std::println("size={}", h.size()); // 1001
}

